250: #define TRHASH_SIZE 13
251: static size_t trhash(void *key, size_t key_length, size_t slots_num)
252: {
253:   size_t keyval = (size_t)*(struct Curl_easy **)key;
254:   (void) key_length;
255: 
256:   return (keyval % slots_num);
257: }
