259: static size_t trhash_compare(void *k1, size_t k1_len, void *k2, size_t k2_len)
260: {
261:   (void)k1_len;
262:   (void)k2_len;
263: 
264:   return *(struct Curl_easy **)k1 == *(struct Curl_easy **)k2;
265: }
